def validate_source_grounding(packet: dict) -> dict:
    """Validate all claims have source attribution."""
    ungrounded = []

    # Check VOC sections
    for pain in packet.get("voc", {}).get("pains", []):
        if not pain.get("source") and pain.get("verbatim_quote"):
            ungrounded.append(f"Pain: {pain.get('statement', 'unknown')}")

    for desire in packet.get("voc", {}).get("desires", []):
        if not desire.get("source") and desire.get("verbatim_quote"):
            ungrounded.append(f"Desire: {desire.get('statement', 'unknown')}")

    for objection in packet.get("voc", {}).get("objections", []):
        if not objection.get("source") and objection.get("verbatim_quote"):
            ungrounded.append(f"Objection: {objection.get('statement', 'unknown')}")

    return {
        "passed": len(ungrounded) == 0,
        "ungrounded_count": len(ungrounded),
        "ungrounded_items": ungrounded
    }


def validate_value_equation_completeness(packet: dict) -> dict:
    """Validate Value Equation inputs are complete."""
    ve = packet.get("value_equation_inputs", {})
    required_fields = ["dream_outcome", "perceived_likelihood", "time_delay", "effort_sacrifice"]

    missing = []
    incomplete = []

    for field in required_fields:
        if field not in ve:
            missing.append(field)
        elif not ve[field].get("current_score"):
            incomplete.append(f"{field}: missing score")
        elif not ve[field].get("optimization_opportunities"):
            incomplete.append(f"{field}: missing optimization opportunities")

    return {
        "passed": len(missing) == 0 and len(incomplete) == 0,
        "missing": missing,
        "incomplete": incomplete
    }


def validate_objection_mapping(packet: dict) -> dict:
    """Validate objections have timing and bonus suggestions."""
    objections = packet.get("voc", {}).get("objections", [])

    missing_timing = []
    missing_bonus = []

    for obj in objections:
        if not obj.get("timing"):
            missing_timing.append(obj.get("statement", "unknown"))
        if not obj.get("potential_bonus_solution"):
            missing_bonus.append(obj.get("statement", "unknown"))

    return {
        "passed": len(missing_timing) == 0 and len(missing_bonus) == 0,
        "objection_count": len(objections),
        "missing_timing": missing_timing,
        "missing_bonus": missing_bonus
    }


def check_usp_terminology(text: str) -> dict:
    """Check for USP terminology that should be UVE."""
    violations = []

    usp_patterns = ["USP", "unique selling proposition", "Unique Selling Proposition"]

    for pattern in usp_patterns:
        if pattern in text:
            violations.append(pattern)

    return {
        "passed": len(violations) == 0,
        "violations": violations,
        "recommendation": "Replace with UVE (Ultimate Value Experience)" if violations else None
    }
